mapper.select:
SELECT site_name, device_type_name AS type, JSON_ARRAYAGG(JSON_OBJECT( 'time', time, 'value', energy )) AS energyJSON FROM ( SELECT id_site, site_name, id_device_type, device_type_name, time, ROUND(SUM(energy), 1) AS energy FROM (
SELECT #{item.id_site} AS id_site, #{item.site_name} AS site_name, #{item.id_device_type} AS id_device_type, #{item.device_type_name} AS device_type_name, MeasuredProduction AS energy, FROM_UNIXTIME(( UNIX_TIMESTAMP(CONVERT_TZ(time, 'UTC', #{item.timezone_value})) DIV 900 )* 900, '%Y-%m-%d %H:%i' ) AS time FROM ${item.datatablename} WHERE id_device = ${item.id} AND ( CASE WHEN #{startDateTime} IS NULL OR #{endDateTime} IS NULL THEN time BETWEEN CONVERT_TZ(DATE_FORMAT(CONVERT_TZ(DATE_SUB(UTC_TIMESTAMP(), INTERVAL 2 DAY), 'UTC', #{item.timezone_value}), '%Y-%m-%d 00:00:00'), #{item.timezone_value}, 'UTC') AND CONVERT_TZ(DATE_FORMAT(CONVERT_TZ(UTC_TIMESTAMP(), 'UTC', #{item.timezone_value}), '%Y-%m-%d 23:59:59'), #{item.timezone_value}, 'UTC') ELSE time BETWEEN CONVERT_TZ(DATE_FORMAT(#{startDateTime}, '%Y-%m-%d 00:00:00'), #{item.timezone_value}, 'UTC') AND CONVERT_TZ(DATE_FORMAT(#{endDateTime}, '%Y-%m-%d 23:59:59'), #{item.timezone_value}, 'UTC') END )
) d GROUP BY id_site, id_device_type, time ) d GROUP BY id_site, id_device_type
